describe('aria-describedby merge', () => {
  it('uses only the hint id when no existing aria-describedby is provided', () => {
    const view = render(<Checkbox id="cb1" label="Email" hint="We will send updates" />);
    const control = screen.getByRole('checkbox', { name: 'Email' });
    expect(control).toHaveAttribute('aria-describedby', 'cb1-hint');
    view.unmount();
  });

  it('preserves existing aria-describedby when no hint is provided', () => {
    const view = render(<Checkbox id="cb2" label="Email" aria-describedby="external-id" />);
    const control = screen.getByRole('checkbox', { name: 'Email' });
    expect(control).toHaveAttribute('aria-describedby', 'external-id');
    view.unmount();
  });

  it('merges existing aria-describedby with hint id without duplicates', () => {
    const view = render(
      <Checkbox id="cb3" label="Email" hint="We will send updates" aria-describedby="external-id" />
    );
    const control = screen.getByRole('checkbox', { name: 'Email' });
    expect(control).toHaveAttribute('aria-describedby', 'external-id cb3-hint');
    view.unmount();
  });

  it('does not duplicate tokens when existing already contains the hint id', () => {
    const view = render(
      <Checkbox id="cb4" label="Email" hint="We will send updates" aria-describedby="cb4-hint" />
    );
    const control = screen.getByRole('checkbox', { name: 'Email' });
    expect(control).toHaveAttribute('aria-describedby', 'cb4-hint');
    view.unmount();
  });
});

describe('Checkbox', () => {
  it('renders a checkbox with a visible label', () => {
    const view: RenderResult = render(<Checkbox label="Subscribe" />);
    expect(screen.getByRole('checkbox', { name: 'Subscribe' })).toBeInTheDocument();
    view.unmount();
  });

  it('throws when label is empty or whitespace', () => {
    const renderCheckbox = () => render(<Checkbox label="   " />);
    expect(renderCheckbox).toThrow('Checkbox label must be a non-empty string.');
  });

  describe('indicator rendering', () => {
    const cases: ReadonlyArray<
      [label: string, checked: CheckboxProps['checked'], rendered: boolean]
    > = [
      ['unchecked', false, false],
      ['checked', true, true]
    ] as const;

    it.each(cases)('shows indicator when %s', (_state, checked, rendered) => {
      const view: RenderResult = render(<Checkbox label="Updates" checked={checked} />);
      const indicator = view.container.querySelector('[data-slot="indicator"]');
      expect(Boolean(indicator)).toBe(rendered);
      view.unmount();
    });
  });

  it('links hint text via aria-describedby when hint is provided', () => {
    const view: RenderResult = render(<Checkbox label="Receive updates" hint="Hint text" />);
    const control = screen.getByRole('checkbox', { name: 'Receive updates' });
    const hint = screen.getByText('Hint text');
    expect(control).toHaveAttribute('aria-describedby', hint.id);
    view.unmount();
  });

  it('sets the disabled attribute on the control when disabled', () => {
    const view: RenderResult = render(<Checkbox label="Disabled" disabled />);
    const control = screen.getByRole('checkbox', { name: 'Disabled' });
    expect(control).toBeDisabled();
    view.unmount();
  });

  it('applies disabled container classes when disabled', () => {
    const view: RenderResult = render(<Checkbox label="Disabled" disabled />);
    const control = screen.getByRole('checkbox', { name: 'Disabled' });
    const container = control.closest('[data-slot="container"]');
    const hasDisabledClasses =
      Boolean(container) &&
      container?.className.includes('opacity-50') &&
      container?.className.includes('pointer-events-none');
    expect(hasDisabledClasses).toBe(true);
    view.unmount();
  });

  it('sets required attribute when required', () => {
    const view: RenderResult = render(<Checkbox label="Terms" required />);
    const control = screen.getByRole('checkbox', { name: 'Terms' });
    expect(control).toBeRequired();
    view.unmount();
  });

  it('submits name and value when the checkbox is checked', async () => {
    const user = userEvent.setup();
    let submittedValues: string[] = [];
    const view: RenderResult = render(
      <form
        onSubmit={event => {
          event.preventDefault();
          const formData = new FormData(event.currentTarget);
          const entries = formData.getAll('notifications');
          submittedValues = entries.flatMap(v => (typeof v === 'string' ? [v] : []));
        }}
      >
        <Checkbox label="Subscribe" name="notifications" value="weekly" checked />
        <button type="submit">Submit</button>
      </form>
    );
    await user.click(screen.getByRole('button', { name: 'Submit' }));
    expect(submittedValues).toEqual(['weekly']);
    view.unmount();
  });

  it('retains focus ring token classes on keyboard focus', async () => {
    const user = userEvent.setup();
    const view: RenderResult = render(
      <div>
        <button type="button">Before</button>
        <Checkbox label="Focus me" />
      </div>
    );
    await user.tab();
    await user.tab();
    const control = screen.getByRole('checkbox', { name: 'Focus me' });
    expect(control.className).toMatch(/focus-visible:ring-comp-border-focus-ring/);
    view.unmount();
  });

  it('applies control base classes from the styleMap/runtime (smoke)', () => {
    const view: RenderResult = render(<Checkbox label="Base classes" />);
    const control = screen.getByRole('checkbox', { name: 'Base classes' });
    expect(control.className).toMatch(/\bborder-2\b/);
    view.unmount();
  });
});
